#[test]
fun test_verify_groth_16_proof_bn254() {
    let curve = bn254();

    // Success case.
    let mut vk_bytes =
        x"e8324a3242be5193eb38cca8761691ce061e89ce86f1fce8fd7ef40808f12da3c67d9ed5667c841f956e11adbbe240ddf37a1e3a4a890600dc88f608b897898e";
    let alpha_bytes =
        x"";
    let gamma_bytes =
        x"240a80664919b9f7490209cff12bfd81c32c272607dc004661c792082cbe282ef826f56a3822ebd72345f86c7ee9872e23f10d1f2dbf43f8aca5dc2ceb5388a5";
    let delta_bytes =
        x"f755df8c90edab48ac5adafef6a5a461902217f392e3aa4c34c0462b700c18164f79018778755980d491647de11ecc51fda2cc17171c4b44485ec37ccd23a69b";
    let pvk = groth16::pvk_from_bytes(vk_bytes, alpha_bytes, gamma_bytes, delta_bytes);

    let inputs_bytes = x"3fd7c445c6845a9399d1a7b8394c16373399a037786c169f16219359d3be840a";
    let inputs = groth16::public_proof_inputs_from_bytes(inputs_bytes);

    let proof_bytes =
        x"dd2ef02e57d6a282df6b7f36c134ab7e55c2e04c5b8cbd7831be18e0e7224623ae8bd6c41637c10cbd02f5e68de6394461f417895ddd264d6f0ddacf68c6cd02feb8881f0efa599139a6faf4223dd8743777c4346cba52322eb466af96f2be9f813af1450f84d6f8029804f60cac1add70ad1a3d4226404f84f4022dc18caa0f";
    let proof = groth16::proof_points_from_bytes(proof_bytes);

    assert!(groth16::verify_groth16_proof(&curve, &pvk, &inputs, &proof) == true);

    // Invalid prepared verifying key.
    vk_bytes.pop_back();
    let invalid_pvk = groth16::pvk_from_bytes(vk_bytes, alpha_bytes, gamma_bytes, delta_bytes);
    assert!(groth16::verify_groth16_proof(&curve, &invalid_pvk, &inputs, &proof) == false);

    // Invalid proof bytes.
    let invalid_proof = groth16::proof_points_from_bytes(x"4a");
    assert!(groth16::verify_groth16_proof(&curve, &pvk, &inputs, &invalid_proof) == false);
}

