    expiry_market_id: ID,
    predict_manager_id: ID,
    order_id: u256,
    owner: address,
    lower_strike: u64,
    higher_strike: u64,
    leverage: u64,
    /// 1e9-scaled range probability quoted at entry.
    entry_probability: u64,
    quantity: u64,
    /// User cash contributed into LP backing, in DUSDC base units.
    contribution: u64,
    trading_fee: u64,
    builder_fee: u64,
    /// EWMA gas-price congestion surcharge retained by the pool, in DUSDC base units.
    penalty_fee: u64,
    builder_code_id: Option<ID>,
    /// Leverage-implied floor seed amount, in DUSDC base units.
    floor_seed_amount: u64,
